class Solution:
    def getMaxDivisibleNumber(self, inputStr, inputDivisor):
        # 校验参数类型，防止模板解析异常后传入非法类型
        if not isinstance(inputStr, str):
            return -1
        if not isinstance(inputDivisor, int) or isinstance(inputDivisor, bool):
            return -1

        n = len(inputStr)

        # 校验字符串长度和除数范围
        if n < 1 or n > 10000:
            return -1
        if inputDivisor < 1 or inputDivisor > 99:
            return -1

        answer = -1
        i = 0

        while i < n:
            ch = inputStr[i]

            # 判断当前字符是否合法：只能是英文大小写字母或数字
            is_digit = '0' <= ch <= '9'
            is_letter = ('a' <= ch <= 'z') or ('A' <= ch <= 'Z')

            if not is_digit and not is_letter:
                return -1

            # 如果当前字符是字母，直接继续
            if not is_digit:
                i += 1
                continue

            # 当前字符是数字，读取完整的连续数字串
            value = 0
            significant_count = 0

            while i < n and '0' <= inputStr[i] <= '9':
                digit = ord(inputStr[i]) - ord('0')

                # 忽略前导零；一旦出现非零数字，后续零也属于有效位
                if digit != 0 or significant_count > 0:
                    significant_count += 1
                    value = value * 10 + digit

                    # 数值范围要求为 0 到 999，超过三位有效数字一定非法
                    if significant_count > 3 or value > 999:
                        return -1

                i += 1

            # 全是前导零的数字串，例如 0、00、000，解析值为 0
            if value % inputDivisor == 0:
                answer = max(answer, value)

        return answer
