```java
class Solution {
    public int getMaxDivisibleNumber(String inputStr, int inputDivisor) {
        // 校验空字符串对象
        if (inputStr == null) {
            return -1;
        }

        int n = inputStr.length();

        // 校验字符串长度和除数范围
        if (n < 1 || n > 10000) {
            return -1;
        }
        if (inputDivisor < 1 || inputDivisor > 99) {
            return -1;
        }

        int answer = -1;
        int i = 0;

        while (i < n) {
            char ch = inputStr.charAt(i);

            // 判断当前字符是否合法：只能是英文大小写字母或数字
            if (!isDigit(ch) && !isLetter(ch)) {
                return -1;
            }

            // 如果当前字符是字母，直接继续
            if (!isDigit(ch)) {
                i++;
                continue;
            }

            // 当前字符是数字，读取完整的连续数字串
            int value = 0;
            int significantCount = 0;

            while (i < n && isDigit(inputStr.charAt(i))) {
                int digit = inputStr.charAt(i) - '0';

                // 忽略前导零；一旦出现非零数字，后续零也属于有效位
                if (digit != 0 || significantCount > 0) {
                    significantCount++;
                    value = value * 10 + digit;

                    // 数值范围要求为 0 到 999，超过三位有效数字一定非法
                    if (significantCount > 3 || value > 999) {
                        return -1;
                    }
                }

                i++;
            }

            // 全是前导零的数字串，例如 0、00、000，解析值为 0
            if (value % inputDivisor == 0) {
                answer = Math.max(answer, value);
            }
        }

        return answer;
    }

    private boolean isDigit(char ch) {
        return ch >= '0' && ch <= '9';
    }

    private boolean isLetter(char ch) {
        return (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z');
    }
}
